  def generateSecureToken(byteLength: Int = SESSION_TOKEN_BYTE_LENGTH): String = {
    val bytes = new Array[Byte](byteLength)
    secureRandom.nextBytes(bytes)
    Base64.getUrlEncoder.withoutPadding().encodeToString(bytes)
